import { component$ } from "@builder.io/qwik";
import { Form, type ActionStore } from "@builder.io/qwik-city";

export interface AddCommentActionInput {
  parentId?: string;
  author: string;
  body: string;
}

export interface AddCommentActionOutput {
  success: boolean;
}

interface ReplyFormProps {
  parentId: number | null;
  action: ActionStore<AddCommentActionOutput, AddCommentActionInput>;
  label?: string;
}

export const ReplyForm = component$<ReplyFormProps>(
  ({ parentId, action, label }) => {
    const parentIdValue = parentId == null ? "" : String(parentId);

    const submittedParentId = action.formData?.get("parentId") ?? null;
    const isThisForm = submittedParentId === parentIdValue;
    const failure =
      action.value && "failed" in action.value && action.value.failed
        ? (action.value as any)
        : undefined;
    const errors = isThisForm ? failure : undefined;

    return (
      <Form action={action} spaReset class="reply-form">
        <input type="hidden" name="parentId" value={parentIdValue} />
        <div class="field">
          <label>
            Name
            <input type="text" name="author" placeholder="Your name" />
          </label>
          {errors?.fieldErrors?.author && (
            <div class="error" data-testid={`error-author-${parentIdValue || "root"}`}>
              {errors.fieldErrors.author}
            </div>
          )}
        </div>
        <div class="field">
          <label>
            {label ?? "Reply"}
            <textarea name="body" placeholder="Write your comment..." />
          </label>
          {errors?.fieldErrors?.body && (
            <div class="error" data-testid={`error-body-${parentIdValue || "root"}`}>
              {errors.fieldErrors.body}
            </div>
          )}
        </div>
        <button type="submit">{label ?? "Reply"}</button>
      </Form>
    );
  },
);

import { component$, useSignal } from "@builder.io/qwik";
import type { ActionStore } from "@builder.io/qwik-city";
import type { CommentNode } from "~/lib/db";
import {
  ReplyForm,
  type AddCommentActionInput,
  type AddCommentActionOutput,
} from "~/components/reply-form/reply-form";

interface CommentProps {
  comment: CommentNode;
  depth: number;
  action: ActionStore<AddCommentActionOutput, AddCommentActionInput>;
}

export const Comment = component$<CommentProps>(({ comment, depth, action }) => {
  const collapsed = useSignal(false);
  const hasReplies = comment.children.length > 0;

  return (
    <li
      class="comment"
      data-comment-id={comment.id}
      data-depth={depth}
    >
      <div class="comment-card">
        <div class="comment-header">
          <span class="comment-author">{comment.author}</span>
          <span class="comment-reply-count" data-reply-count={comment.replyCount}>
            {comment.replyCount} {comment.replyCount === 1 ? "reply" : "replies"}
          </span>
        </div>

        <p class="comment-body">{comment.body}</p>

        <div class="comment-actions">
          {hasReplies && (
            <button
              type="button"
              class="toggle-button"
              data-testid={`toggle-${comment.id}`}
              onClick$={() => (collapsed.value = !collapsed.value)}
            >
              {collapsed.value
                ? `Expand (${comment.children.length})`
                : `Collapse (${comment.children.length})`}
            </button>
          )}
        </div>

        <details class="reply-details">
          <summary>Reply</summary>
          <ReplyForm parentId={comment.id} action={action} label="Reply" />
        </details>
      </div>

      {hasReplies && (
        <ul
          class="comment-children"
          data-testid={`children-${comment.id}`}
          style={{ display: collapsed.value ? "none" : undefined }}
        >
          {comment.children.map((child) => (
            <Comment key={child.id} comment={child} depth={depth + 1} action={action} />
          ))}
        </ul>
      )}
    </li>
  );
});

